class Solution:
    def countSymmetricIntegers(self, low: int, high: int) -> int:
        count = 0
        for num in range(low, high + 1):
            s = str(num)
            if len(s) % 2 != 0:
                continue
            mid = len(s) // 2
            if sum(int(digit) for digit in s[:mid]) == sum(int(digit) for digit in s[mid:]):
                count += 1
        return count
